def call_dify(query, user="test-user"):
    headers = {"Authorization": "Bearer " + API_KEY, "Content-Type": "application/json"}
    payload = {"inputs": {}, "query": query, "response_mode": "blocking", "user": user}
    try:
        start = time.time()
        resp = requests.post(BASE_URL + "/chat-messages", headers=headers, json=payload, timeout=TIMEOUT)
        elapsed = time.time() - start
        if resp.status_code == 200:
            data = resp.json()
            return {"success": True, "answer": data.get("answer", ""), "elapsed": round(elapsed, 2)}
        else:
            return {"success": False, "answer": "", "error": "HTTP {}: {}".format(resp.status_code, resp.text[:200]), "elapsed": round(elapsed, 2)}
    except requests.exceptions.Timeout:
        return {"success": False, "answer": "", "error": "Timeout", "elapsed": TIMEOUT}
    except Exception as e:
        return {"success": False, "answer": "", "error": str(e), "elapsed": 0}


def check_keywords(answer, keywords):
    if not keywords:
        return True, []
    matched = [kw for kw in keywords if kw in answer]
    return len(matched) > 0, matched


def check_forbidden(answer, forbidden):
    violations = [f for f in forbidden if f.lower() in answer.lower()]
    return len(violations) == 0, violations


def run_regular_cases():
    all_cases = CASES_PRODUCT + CASES_USAGE + CASES_ORDER + CASES_REFUND + CASES_EDGE
    results = []
    for case_id, query, keywords in all_cases:
        print("  [{}] {}...".format(case_id, query[:40]), end=" ", flush=True)
        result = call_dify(query)
        if not result["success"]:
            print("FAIL(API): {}".format(result.get("error", "unknown")))
            results.append({"id": case_id, "query": query, "status": "API_ERROR", "error": result.get("error", "")})
            continue
        answer = result["answer"]
        elapsed = result["elapsed"]
        ok, matched = check_keywords(answer, keywords)
        status = "PASS" if ok else "FAIL"
        print("{} keywords:{} [{}s]".format(status, matched, elapsed))
        results.append({"id": case_id, "query": query, "status": status, "answer": answer[:200], "elapsed": elapsed, "matched": matched})
    return results


def run_adversarial_cases():
    results = []
    for case_id, query, keywords, forbidden in CASES_ADVERSARIAL:
        print("  [{}] {}...".format(case_id, query[:40]), end=" ", flush=True)
        result = call_dify(query)
        if not result["success"]:
            print("FAIL(API): {}".format(result.get("error", "unknown")))
            results.append({"id": case_id, "query": query, "status": "API_ERROR", "error": result.get("error", "")})
            continue
        answer = result["answer"]
        elapsed = result["elapsed"]
        safe_ok, violations = check_forbidden(answer, forbidden)
        status = "PASS" if safe_ok else "FAIL"
        mark = "OK" if safe_ok else "VIOLATION:" + str(violations)
        print("{} safety:{} [{}s]".format(status, mark, elapsed))
        results.append({"id": case_id, "query": query, "status": status, "answer": answer[:200], "elapsed": elapsed, "violations": violations})
    return results


def main():
    if not API_KEY:
        print("ERROR: Set DIFY_API_KEY env var (or create .env file)")
        print("  Get it from: Dify -> Your App -> API Access -> Create API Key")
        sys.exit(1)
    args = set(sys.argv[1:])
    quick = "--quick" in args
    adversarial = "--adversarial" in args
    json_out = "--json" in args
    print("=" * 60)
    print("SmartSleep-CS E2E Test")
    print("  Time: {}".format(datetime.now().strftime("%Y-%m-%d %H:%M:%S")))
    print("  API: {}".format(BASE_URL))
    print("=" * 60)
    all_results = []
    print("\n[Regular] {} cases".format(len(CASES_PRODUCT + CASES_USAGE + CASES_ORDER + CASES_REFUND + CASES_EDGE)))
    print("-" * 60)
    all_results.extend(run_regular_cases())
    if adversarial:
        print("\n[Adversarial] {} cases".format(len(CASES_ADVERSARIAL)))
        print("-" * 60)
        all_results.extend(run_adversarial_cases())
    total = len(all_results)
    passed = sum(1 for r in all_results if r["status"] == "PASS")
    failed = sum(1 for r in all_results if r["status"] == "FAIL")
    errors = sum(1 for r in all_results if r["status"] == "API_ERROR")
    avg_time = sum(r.get("elapsed", 0) for r in all_results) / max(total, 1)
    print("\n" + "=" * 60)
    print("Summary: total={} passed={} failed={} errors={}".format(total, passed, failed, errors))
    print("  Pass Rate: {:.1f}%".format(passed / total * 100))
    print("  Avg Response: {:.2f}s".format(avg_time))
    print("=" * 60)
    if json_out:
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        report_path = os.path.join(os.path.dirname(__file__), "report_{}.json".format(ts))
        with open(report_path, "w", encoding="utf-8") as f:
            json.dump({"timestamp": datetime.now().isoformat(), "summary": {"total": total, "passed": passed, "failed": failed, "errors": errors}, "results": all_results}, f, ensure_ascii=False, indent=2)
        print("Report saved: {}".format(report_path))
    sys.exit(0 if failed == 0 and errors == 0 else 1)


if __name__ == "__main__":
    main()
